/**
 * @param trivial_accept - set if the previous BSP traversal guaranteed
 *   all vertices are on-screen; skips per-vertex clip tests
 */
function R_AliasSetUpTransform(trivial_accept: number): void {
  for (let i = 0; i < 3; i++) {
    aliastransform[i][0] = rotationMatrix[0][i];
    aliastransform[i][1] = rotationMatrix[1][i];
    aliastransform[i][2] = rotationMatrix[2][i];
  }
}
